   158→/**
   159→ * Map database row to EmailMessage interface
   160→ */
   161→function mapRowToEmailMessage(row: DatabaseRow): EmailMessage {
   162→  // Parse date safely
   163→  const sentAt = row.sent_at ? new Date(row.sent_at) : new Date();
   164→
   165→  // Parse from address
   166→  const fromSimple = typeof row.from_simple === 'string' ? JSON.parse(row.from_simple) : row.from_simple;
   167→  const from: EmailAddress = {
   168→    email: (fromSimple.address as string) || (fromSimple.email as string) || '',
   169→    name: fromSimple.name as string | undefined,
   170→    raw: ((fromSimple.raw || fromSimple.address || fromSimple.email) as string) || '',
   171→  };
   172→
   173→  // Parse to addresses
   174→  const toAddrs = typeof row.to_addrs === 'string' ? JSON.parse(row.to_addrs) : row.to_addrs;
   175→  const to: EmailAddress[] = (Array.isArray(toAddrs) ? toAddrs : []).map((addr: Record<string, unknown>) => ({
   176→    email: (addr.address as string) || (addr.email as string) || '',
   177→    name: addr.name as string | undefined,
   178→    raw: ((addr.raw || addr.address || addr.email) as string) || '',
   179→  }));
   180→
   181→  // Parse headers
   182→  const headers = typeof row.headers === 'string' ? JSON.parse(row.headers) : row.headers;
   183→  const headerArray: EmailHeader[] = Array.isArray(headers)
   184→    ? headers.map((h: Record<string, unknown>) => ({
   185→        name: (h.name as string) || '',
   186→        value: (h.value as string) || '',
   187→      }))
   188→    : [];
   189→
   190→  // Parse raw Gmail payload
   191→  const rawPayload = typeof row.raw === 'string' ? JSON.parse(row.raw) : row.raw;
   192→
   193→  // Parse reply-to if exists
   194→  let replyTo: EmailAddress[] | undefined;
   195→  if (row.reply_to_addrs) {
   196→    const replyToAddrs = typeof row.reply_to_addrs === 'string' ? JSON.parse(row.reply_to_addrs) : row.reply_to_addrs;
   197→    replyTo = (Array.isArray(replyToAddrs) ? replyToAddrs : []).map((addr: Record<string, unknown>) => ({
   198→      email: (addr.address as string) || (addr.email as string) || '',
   199→      name: addr.name as string | undefined,
   200→      raw: ((addr.raw || addr.address || addr.email) as string) || '',
   201→    }));
   202→  }
   203→
   204→  // Type guard for payload - Gmail API response structure
   205→  const payload = rawPayload as
   206→    | { payload?: { mimeType?: string; body?: unknown; parts?: unknown }; snippet?: string }
   207→    | undefined;
   208→
   209→  return {
   210→    id: row.gmail_id,
   211→    threadId: row.gmail_thread_id,
   212→    gmailLabels: Array.isArray(row.label_ids) ? row.label_ids : [],
   213→    payload: {
   214→      mimeType: (payload?.payload?.mimeType as string) || 'text/plain',
   215→      headers: headerArray,
   216→      body: payload?.payload?.body as MessagePartBody | undefined,
   217→      parts: payload?.payload?.parts as MessagePart[] | undefined,
   218→    },
   219→    subject: row.subject || '',
   220→    from,
   221→    to,
   222→    replyTo,
   223→    date: sentAt,
   224→    messageId: row.message_id_hdr,
   225→    bodyPlain: row.body_text,
   226→    bodyHtml: row.body_html,
   227→    snippet: payload?.snippet as string | undefined,
   228→    sizeEstimate: row.size_estimate,
   229→    isProcessed: !!row.session_id, // Has classification session
   230→    processingSessionId: row.session_id ? String(row.session_id) : undefined,
   231→    processedAt: row.completed_at ? new Date(row.completed_at) : undefined,
   232→    processingPriority: 0, // Default priority for testing
   233→  };
   234→}
