   236→/**
   237→ * Fetch emails within specified date range
   238→ *
   239→ * @param startDate - Start of date range (inclusive)
   240→ * @param endDate - End of date range (inclusive)
   241→ * @param limit - Maximum number of emails to return (default: 100)
   242→ * @returns Array of EmailMessage objects
   243→ */
   244→export async function fetchEmailsByDateRange(
   245→  startDate: Date,
   246→  endDate: Date,
   247→  limit: number = 100
   248→): Promise<EmailMessage[]> {
   249→  // Validate date range
   250→  if (startDate > endDate) {
   251→    throw new Error('Invalid date range: start date must be before end date');
   252→  }
   253→
   254→  const pool = getPool();
   255→
   256→  const query = `
   257→    SELECT
   258→      gm.gmail_id,
   259→      gm.gmail_thread_id,
   260→      gm.label_ids,
   261→      gm.subject,
   262→      gm.sent_at,
   263→      gm.message_id_hdr,
   264→      gm.from_simple,
   265→      gm.to_addrs,
   266→      gm.reply_to_addrs,
   267→      gm.headers,
   268→      gm.body_text,
   269→      gm.body_html,
   270→      gm.raw,
   271→      gm.size_estimate,
   272→      cs.session_id,
   273→      cs.completed_at
   274→    FROM email.gmail_message gm
   275→    LEFT JOIN LATERAL (
   276→      SELECT session_id, completed_at
   277→      FROM email.classification_session
   278→      WHERE gmail_id = gm.gmail_id
   279→      ORDER BY started_at DESC
   280→      LIMIT 1
   281→    ) cs ON true
   282→    WHERE gm.sent_at >= $1 AND gm.sent_at <= $2
   283→    ORDER BY gm.sent_at DESC
   284→    LIMIT $3
   285→  `;
   286→
   287→  try {
   288→    const result = await pool.query(query, [startDate, endDate, limit]);
   289→    return result.rows.map(mapRowToEmailMessage);
   290→  } catch (error) {
   291→    throw new Error(`Failed to fetch emails by date range: ${(error as Error).message}`);
   292→  }
   293→}
