   397→/**
   398→ * Encode cursor for pagination
   399→ */
   400→function encodeCursor(cursor: Cursor): string {
   401→  const json = JSON.stringify(cursor);
   402→  return Buffer.from(json).toString('base64');
   403→}
   404→
   405→/**
   406→ * Decode cursor for pagination
   407→ */
   408→function decodeCursor(cursorStr: string): Cursor {
   409→  try {
   410→    const json = Buffer.from(cursorStr, 'base64').toString('utf-8');
   411→    const cursor = JSON.parse(json) as Cursor;
   412→
   413→    // Validate cursor structure
   414→    if (!cursor.timestamp || !cursor.id) {
   415→      throw new Error('Invalid cursor structure');
   416→    }
   417→
   418→    // Validate timestamp format
   419→    if (isNaN(new Date(cursor.timestamp).getTime())) {
   420→      throw new Error('Invalid cursor timestamp');
   421→    }
   422→
   423→    return cursor;
   424→  } catch (error) {
   425→    throw new Error(`Invalid cursor format: ${(error as Error).message}`);
   426→  }
   427→}
