   429→/**
   430→ * Build WHERE clause from criteria
   431→ */
   432→function buildWhereClause(
   433→  criteria: EmailQueryCriteria,
   434→  paramOffset: number = 0
   435→): { clause: string; params: unknown[] } {
   436→  const conditions: string[] = [];
   437→  const params: unknown[] = [];
   438→  let paramIndex = paramOffset + 1;
   439→
   440→  // Subject filter
   441→  if (criteria.subject) {
   442→    conditions.push(`gm.subject ILIKE $${paramIndex}`);
   443→    params.push(`%${criteria.subject}%`);
   444→    paramIndex++;
   445→  }
   446→
   447→  // From filter
   448→  if (criteria.from) {
   449→    conditions.push(`(gm.from_simple::text ILIKE $${paramIndex})`);
   450→    params.push(`%${criteria.from}%`);
   451→    paramIndex++;
   452→  }
   453→
   454→  // Body contains filter
   455→  if (criteria.bodyContains) {
   456→    conditions.push(
   457→      `(COALESCE(gm.body_text, '') ILIKE $${paramIndex} OR COALESCE(gm.body_html, '') ILIKE $${paramIndex})`
   458→    );
   459→    params.push(`%${criteria.bodyContains}%`);
   460→    paramIndex++;
   461→  }
   462→
   463→  // Date range filter
   464→  if (criteria.dateRange) {
   465→    conditions.push(`gm.sent_at >= $${paramIndex}`);
   466→    params.push(criteria.dateRange.start);
   467→    paramIndex++;
   468→
   469→    conditions.push(`gm.sent_at <= $${paramIndex}`);
   470→    params.push(criteria.dateRange.end);
   471→    paramIndex++;
   472→  }
   473→
   474→  // Gmail labels filter (OR logic)
   475→  if (criteria.gmailLabels && criteria.gmailLabels.length > 0) {
   476→    conditions.push(`gm.label_ids && $${paramIndex}::text[]`);
   477→    params.push(criteria.gmailLabels);
   478→    paramIndex++;
   479→  }
   480→
   481→  // Processing status filter
   482→  if (criteria.isProcessed !== undefined) {
   483→    if (criteria.isProcessed) {
   484→      conditions.push('cs.session_id IS NOT NULL');
   485→    } else {
   486→      conditions.push('cs.session_id IS NULL');
   487→    }
   488→  }
   489→
   490→  // Primary category filter (requires JOIN with session_categories)
   491→  if (criteria.primaryCategory) {
   492→    conditions.push(`sc.is_primary = true`);
   493→    // Note: We need to join with category table to filter by code
   494→    conditions.push(`cat.code = $${paramIndex}`);
   495→    params.push(criteria.primaryCategory);
   496→    paramIndex++;
   497→  }
   498→
   499→  // Minimum confidence filter (requires JOIN with classification_session)
   500→  if (criteria.minConfidence !== undefined) {
   501→    conditions.push(`cs.confidence >= $${paramIndex}`);
   502→    params.push(criteria.minConfidence);
   503→    paramIndex++;
   504→  }
   505→
   506→  // Urgency filter (requires JOIN with detected_attribute)
   507→  if (criteria.urgency) {
   508→    conditions.push(`da.attribute_name = 'urgency'`);
   509→    conditions.push(`da.attribute_value = $${paramIndex}`);
   510→    params.push(criteria.urgency);
   511→    paramIndex++;
   512→  }
   513→
   514→  const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
   515→  return { clause: whereClause, params };
   516→}
   517→
   518→/**
   519→ * Build FROM clause with necessary JOINs based on criteria
   520→ */
   521→function buildFromClause(criteria: EmailQueryCriteria, pagination?: PaginationOptions): string {
   522→  let fromClause = 'FROM email.gmail_message gm';
   523→
   524→  // Always LEFT JOIN classification_session for processing status
   525→  fromClause += `
   526→    LEFT JOIN LATERAL (
   527→      SELECT session_id, completed_at, final_confidence as confidence
   528→      FROM email.classification_session
   529→      WHERE gmail_id = gm.gmail_id
   530→      ORDER BY started_at DESC
   531→      LIMIT 1
   532→    ) cs ON true`;
   533→
   534→  // JOIN session_categories and category if filtering by category
   535→  if (criteria.primaryCategory) {
   536→    fromClause += `
   537→    LEFT JOIN email.session_categories sc ON cs.session_id = sc.session_id
   538→    LEFT JOIN email.category cat ON sc.category_code = cat.code`;
   539→  }
   540→
   541→  // JOIN detected_attributes if filtering by urgency
   542→  if (criteria.urgency) {
   543→    fromClause += `
   544→    LEFT JOIN email.detected_attributes da ON cs.session_id = da.session_id`;
   545→  }
   546→
   547→  // JOIN for confidence-based sorting
   548→  if (pagination?.sortBy === 'confidence') {
   549→    // Already have cs.confidence from classification_session JOIN
   550→  }
   551→
   552→  return fromClause;
   553→}
   554→
   555→/**
   556→ * Build ORDER BY clause
   557→ */
   558→function buildOrderByClause(pagination?: PaginationOptions): string {
   559→  const sortBy = pagination?.sortBy || 'date';
   560→  const sortOrder = pagination?.sortOrder || 'desc';
   561→
   562→  if (sortBy === 'confidence') {
   563→    return `ORDER BY cs.confidence ${sortOrder.toUpperCase()}, gm.sent_at DESC`;
   564→  }
   565→
   566→  // Default: sort by date
   567→  return `ORDER BY gm.sent_at ${sortOrder.toUpperCase()}`;
   568→}
