   570→/**
   571→ * Validate criteria and pagination options
   572→ */
   573→function validateCriteriaAndPagination(criteria: EmailQueryCriteria, pagination?: PaginationOptions): void {
   574→  // Validate date range
   575→  if (criteria.dateRange) {
   576→    if (criteria.dateRange.start > criteria.dateRange.end) {
   577→      throw new Error('Invalid date range: start date must be before end date');
   578→    }
   579→  }
   580→
   581→  // Validate confidence range
   582→  if (criteria.minConfidence !== undefined) {
   583→    if (criteria.minConfidence < 0 || criteria.minConfidence > 1) {
   584→      throw new Error('Invalid confidence: must be between 0.0 and 1.0');
   585→    }
   586→  }
   587→
   588→  // Validate pagination limit
   589→  if (pagination?.limit !== undefined) {
   590→    if (pagination.limit < 0) {
   591→      throw new Error('Invalid limit: must be non-negative');
   592→    }
   593→    if (pagination.limit > 1000) {
   594→      throw new Error('Limit exceeds maximum allowed value of 1000');
   595→    }
   596→  }
   597→}
