   599→/**
   600→ * Fetch emails with criteria-based selection and pagination (T048)
   601→ *
   602→ * @param criteria - Query criteria for filtering
   603→ * @param pagination - Pagination options (limit, cursor, sort)
   604→ * @returns Paginated result with email messages
   605→ */
   606→export async function fetchEmailsByCriteria(
   607→  criteria: EmailQueryCriteria,
   608→  pagination?: PaginationOptions
   609→): Promise<PaginatedResult<EmailMessage>> {
   610→  // Validate inputs
   611→  validateCriteriaAndPagination(criteria, pagination);
   612→
   613→  const pool = getPool();
   614→
   615→  // Pagination defaults
   616→  const limit = pagination?.limit || 50;
   617→  const includeTotalCount = pagination?.includeTotalCount || false;
   618→
   619→  // Decode cursor if provided
   620→  let cursorData: Cursor | null = null;
   621→  if (pagination?.cursor) {
   622→    cursorData = decodeCursor(pagination.cursor);
   623→  }
   624→
   625→  // Build query components
   626→  const { clause: whereClause, params } = buildWhereClause(criteria);
   627→  const fromClause = buildFromClause(criteria, pagination);
   628→  const orderByClause = buildOrderByClause(pagination);
   629→
   630→  // Add cursor conditions to WHERE clause
   631→  let cursorCondition = '';
   632→  let cursorParams: unknown[] = [];
   633→  if (cursorData) {
   634→    const cursorParamIndex = params.length + 1;
   635→    const sortOrder = pagination?.sortOrder || 'desc';
   636→
   637→    if (sortOrder === 'desc') {
   638→      cursorCondition = `(gm.sent_at < $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id < $${cursorParamIndex + 1}))`;
   639→    } else {
   640→      cursorCondition = `(gm.sent_at > $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id > $${cursorParamIndex + 1}))`;
   641→    }
   642→    cursorParams = [cursorData.timestamp, cursorData.id];
   643→  }
   644→
   645→  // Combine WHERE clause with cursor condition
   646→  let finalWhereClause = whereClause;
   647→  if (cursorCondition) {
   648→    if (whereClause) {
   649→      // Already have WHERE clause, append with AND
   650→      finalWhereClause = `${whereClause} AND ${cursorCondition}`;
   651→    } else {
   652→      // No WHERE clause yet, add it with cursor condition
   653→      finalWhereClause = `WHERE ${cursorCondition}`;
   654→    }
   655→  }
   656→
   657→  // Construct main query (fetch limit + 1 to determine hasMore)
   658→  const query = `
   659→    SELECT
   660→      gm.gmail_id,
   661→      gm.gmail_thread_id,
   662→      gm.label_ids,
   663→      gm.subject,
   664→      gm.sent_at,
   665→      gm.message_id_hdr,
   666→      gm.from_simple,
   667→      gm.to_addrs,
   668→      gm.reply_to_addrs,
   669→      gm.headers,
   670→      gm.body_text,
   671→      gm.body_html,
   672→      gm.raw,
   673→      gm.size_estimate,
   674→      cs.session_id,
   675→      cs.completed_at
   676→    ${fromClause}
   677→    ${finalWhereClause}
   678→    ${orderByClause}
   679→    LIMIT $${params.length + cursorParams.length + 1}
   680→  `;
   681→
   682→  const queryParams = [...params, ...cursorParams, limit + 1];
   683→
   684→  try {
   685→    // Execute main query
   686→    const result = await pool.query(query, queryParams);
   687→
   688→    // Determine hasMore and prepare items
   689→    const hasMore = result.rows.length > limit;
   690→    const items = result.rows.slice(0, limit).map(mapRowToEmailMessage);
   691→
   692→    // Generate nextCursor if hasMore
   693→    let nextCursor: string | undefined;
   694→    if (hasMore && items.length > 0) {
   695→      const lastItem = items[items.length - 1];
   696→      nextCursor = encodeCursor({
   697→        timestamp: lastItem.date.toISOString(),
   698→        id: lastItem.id,
   699→      });
   700→    }
   701→
   702→    // Fetch total count if requested (separate query for performance)
   703→    let totalCount: number | undefined;
   704→    if (includeTotalCount) {
   705→      const countQuery = `
   706→        SELECT COUNT(*) as count
   707→        ${fromClause}
   708→        ${whereClause}
   709→      `;
   710→
   711→      const countResult = await pool.query(countQuery, params);
   712→      totalCount = parseInt(countResult.rows[0].count, 10);
   713→    }
   714→
   715→    return {
   716→      items,
   717→      pagination: {
   718→        limit,
   719→        hasMore,
   720→        nextCursor,
   721→        totalCount,
   722→      },
   723→    };
   724→  } catch (error) {
   725→    throw new Error(`Failed to fetch emails by criteria: ${(error as Error).message}`);
   726→  }
   727→}
